using Microsoft.EntityFrameworkCore;

// ── Cosmos DB EF Core 9 breaking-change fixes ──────────────────────────
//
// 1. DISCRIMINATOR RENAME  (was "Discriminator", now defaults to "$type")
//    Existing documents store "Discriminator". We must keep the old name
//    so EF9 can still read them.
//
// 2. SYNC QUERIES REMOVED
//    ToList(), First(), Single(), etc. now throw at runtime.
//    Use ToListAsync(), FirstAsync(), SingleAsync(), etc.

class CosmosDbContext : DbContext
{
    public DbSet<Vehicle> Vehicles => Set<Vehicle>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX 1: Preserve the legacy discriminator property name for
        // containers that already have documents with "Discriminator".
        modelBuilder.Entity<Vehicle>()
            .HasDiscriminator<string>("Discriminator");
    }

    // FIX 2: Replace all synchronous queries with async equivalents.
    //
    // BEFORE (EF8 – compiled but used sync-over-async internally):
    //   var cars = db.Vehicles.Where(v => v.Type == "Car").ToList();
    //   var first = db.Vehicles.First(v => v.Id == id);
    //
    // AFTER (EF9 – only async is supported):
    //   var cars = await db.Vehicles.Where(v => v.Type == "Car").ToListAsync();
    //   var first = await db.Vehicles.FirstAsync(v => v.Id == id);
}

class Vehicle
{
    public string Id { get; set; } = null!;
    public string Type { get; set; } = null!;
}

